import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormatWithNormalValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertNotNull(result);
        String expected = "a,b,c";
        assertEquals(expected, result);
    }

    @Test
    public void testFormatWithEmptyValues() {
        String result = csvFormat.format();
        // Empty record results in empty string
        assertEquals("", result);
    }

    @Test
    public void testFormatWithNullValues() {
        String result = csvFormat.format((Object) null, "b", null);
        // nulls will print as empty (default), so commas between values remain
        assertEquals(",b,", result);
    }

    @Test
    public void testFormatIOExceptionIsWrapped() throws Exception {
        // Create a spy of CSVPrinter to throw IOException on printRecord(Object...)
        CSVPrinter spyPrinter = spy(new CSVPrinter(new StringWriter(), CSVFormat.DEFAULT));
        // Disambiguate the overloaded printRecord method by using doThrow().when() with an explicit lambda
        doThrow(new IOException("io exception")).when(spyPrinter).printRecord((Object[]) any());

        // Create a CSVFormat subclass that overrides format(...) to use spyPrinter
        CSVFormat formatWithMock = new CSVFormatWrapper(spyPrinter);

        IllegalStateException exception = assertThrows(IllegalStateException.class,
                () -> formatWithMock.format("a", "b"));
        assertTrue(exception.getMessage().isEmpty());
        assertTrue(exception.getCause() instanceof IOException);
        assertEquals("io exception", exception.getCause().getMessage());
    }

    // Helper subclass to override format method
    private static class CSVFormatWrapper extends CSVFormat {
        private final CSVPrinter spyPrinter;

        CSVFormatWrapper(CSVPrinter spyPrinter) {
            super(CSVFormat.DEFAULT.getDelimiter(), CSVFormat.DEFAULT.getQuoteCharacter(), CSVFormat.DEFAULT.getQuoteMode(),
                    CSVFormat.DEFAULT.getCommentMarker(), CSVFormat.DEFAULT.getEscapeCharacter(),
                    CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(), CSVFormat.DEFAULT.getIgnoreEmptyLines(),
                    CSVFormat.DEFAULT.getRecordSeparator(), CSVFormat.DEFAULT.getNullString(),
                    CSVFormat.DEFAULT.getHeaderComments(), CSVFormat.DEFAULT.getHeader(),
                    CSVFormat.DEFAULT.getSkipHeaderRecord(), CSVFormat.DEFAULT.getAllowMissingColumnNames(),
                    CSVFormat.DEFAULT.getIgnoreHeaderCase(), CSVFormat.DEFAULT.getTrim(),
                    CSVFormat.DEFAULT.getTrailingDelimiter(), CSVFormat.DEFAULT.getAutoFlush());
            this.spyPrinter = spyPrinter;
        }

        @Override
        public String format(final Object... values) {
            try {
                spyPrinter.printRecord(values);
                return spyPrinter.out.toString().trim();
            } catch (final IOException e) {
                throw new IllegalStateException(e);
            }
        }
    }
}
